import type { FishSpecies, PlantSpecies, TankSize, Disease, Article, CompatibilityResult } from '@/types';

// ============================================================
// In production, these functions read from JSON data files
// in /src/data/ that are generated by build scripts from the
// master database. For now, they export stub functions that
// will be populated as data is added.
// ============================================================

const DATA_DIR = '@/data';

// ============================================================
// FISH
// ============================================================
export async function getAllFish(): Promise<FishSpecies[]> {
  try {
    const data = await import('@/data/fish.json');
    return data.default as FishSpecies[];
  } catch {
    return [];
  }
}

export async function getFishBySlug(slug: string): Promise<FishSpecies | null> {
  const all = await getAllFish();
  return all.find((f) => f.slug === slug) ?? null;
}

export async function getFishByCategory(category: 'freshwater' | 'saltwater'): Promise<FishSpecies[]> {
  const all = await getAllFish();
  return all.filter((f) => f.category === category);
}

export async function getFishSlugs(): Promise<string[]> {
  const all = await getAllFish();
  return all.map((f) => f.slug);
}

