// ============================================================
// COMPATIBILITY
// ============================================================
export async function getCompatibility(fishA: string, fishB: string): Promise<CompatibilityResult | null> {
  try {
    const data = await import('@/data/compatibility.json');
    const matrix = data.default as CompatibilityResult[];
    return (
      matrix.find(
        (c) =>
          (c.fishA === fishA && c.fishB === fishB) ||
          (c.fishA === fishB && c.fishB === fishA)
      ) ?? null
    );
  } catch {
    return null;
  }
}

