// ============================================================
// SITEMAP HELPERS
// ============================================================
export async function getAllSitemapUrls(): Promise<{ url: string; lastmod: string; priority: number }[]> {
  const [fish, plants, tankSizes, diseases, articles] = await Promise.all([
    getAllFish(),
    getAllPlants(),
    getAllTankSizes(),
    getAllDiseases(),
    getAllArticles(),
  ]);

  const urls: { url: string; lastmod: string; priority: number }[] = [];
  const now = new Date().toISOString().split('T')[0];

  // Static pages
  urls.push({ url: '/', lastmod: now, priority: 1.0 });
  urls.push({ url: '/calculators/tank-volume', lastmod: now, priority: 0.8 });
  urls.push({ url: '/calculators/stocking', lastmod: now, priority: 0.8 });
  urls.push({ url: '/calculators/heater-size', lastmod: now, priority: 0.8 });

  // Programmatic pages
  fish.forEach((f) => urls.push({ url: `/fish/${f.slug}`, lastmod: now, priority: 0.7 }));
  plants.forEach((p) => urls.push({ url: `/plants/${p.slug}`, lastmod: now, priority: 0.7 }));
  tankSizes.forEach((t) => urls.push({ url: `/tank-sizes/${t.slug}`, lastmod: now, priority: 0.8 }));
  diseases.forEach((d) => urls.push({ url: `/diseases/${d.slug}`, lastmod: now, priority: 0.6 }));

  // Editorial articles
  articles.forEach((a) =>
    urls.push({ url: `/${a.pillar}/${a.slug}`, lastmod: a.updatedAt, priority: 0.8 })
  );

  return urls;
}
